/**
 * Curio app entrypoint surface.
 *
 * @remarks
 * Re-export the assembled API and server helpers so tests and embedding code
 * can import the generated app without reaching into `src/` directly.
 */
export { httpApi } from "@/http/api/index.ts";
export { createHttpServer, startHttpServer } from "@/http/server.ts";

import { createSuperAdmin } from "@/db/admin/create-superadmin.ts";
import { closeDatabase, db, prepareDatabase } from "@/db/index.ts";
import { LOG } from "@/tools/logger/index.ts";

const encoder = new TextEncoder();
const decoder = new TextDecoder();

const ENTER_BYTES = new Set([10, 13]);
const BACKSPACE_BYTES = new Set([8, 127]);
const CTRL_C_BYTE = 3;

const writeStdout = async (value: string): Promise<void> => {
  await Deno.stdout.write(encoder.encode(value));
};

const promptRequired = (label: string): string => {
  const value = globalThis.prompt(`${label}:`);

  if (value === null) {
    throw new Error(`${label} input was cancelled.`);
  }

  const trimmedValue = value.trim();

  if (!trimmedValue) {
    throw new Error(`${label} cannot be empty.`);
  }

  return trimmedValue;
};

const promptSecret = async (label: string): Promise<string> => {
  if (!Deno.stdin.isTerminal()) {
    throw new Error("Secret input requires an interactive terminal.");
  }

  await writeStdout(`${label}: `);
  Deno.stdin.setRaw(true);

  const buffer = new Uint8Array(1);
  let value = "";

  try {
    while (true) {
      const read = await Deno.stdin.read(buffer);

      if (read === null) {
        throw new Error(`${label} input was interrupted.`);
      }

      const byte = buffer[0];

      if (byte === CTRL_C_BYTE) {
        await writeStdout("\n");
        throw new Error(`${label} input was cancelled.`);
      }

      if (ENTER_BYTES.has(byte)) {
        await writeStdout("\n");
        break;
      }

      if (BACKSPACE_BYTES.has(byte)) {
        value = value.slice(0, -1);
        continue;
      }

      value += decoder.decode(buffer.subarray(0, read));
    }
  } finally {
    Deno.stdin.setRaw(false);
  }

  if (!value) {
    throw new Error(`${label} cannot be empty.`);
  }

  return value;
};

const promptPassword = async (): Promise<string> => {
  const password = await promptSecret("Superadmin password");
  const confirmation = await promptSecret("Confirm superadmin password");

  if (password !== confirmation) {
    throw new Error("Superadmin password confirmation does not match.");
  }

  return password;
};

const formatCliError = (error: unknown): string => {
  if (!(error instanceof Error)) {
    return String(error);
  }

  const lines = [error.message];
  const cause = error.cause;

  if (cause && typeof cause === "object") {
    const typedCause = cause as Record<string, unknown>;

    if (typeof typedCause.message === "string") {
      lines.push(`cause: ${typedCause.message}`);
    }

    if (typeof typedCause.code === "string") {
      lines.push(`code: ${typedCause.code}`);
    }

    if (typeof typedCause.detail === "string") {
      lines.push(`detail: ${typedCause.detail}`);
    }

    if (typeof typedCause.hint === "string") {
      lines.push(`hint: ${typedCause.hint}`);
    }
  }

  return lines.join("\n");
};

if (import.meta.main) {
  let exitCode = 0;

  try {
    LOG.debug("Preparing database for superadmin creation");
    await prepareDatabase();

    const email = promptRequired("Superadmin email");
    const password = await promptPassword();
    const user = await createSuperAdmin({
      email,
      password,
      db,
    });

    LOG.info(`Superadmin created: ${user.email} (${user.id})`);
  } catch (error) {
    const message = formatCliError(error);
    LOG.error(message);
    exitCode = 1;
  } finally {
    LOG.debug("Closing database after superadmin command");
    await closeDatabase();

    if (exitCode !== 0) {
      Deno.exit(exitCode);
    }
  }
}

let didLoadEnv = false;

const ENV_FILE_URL = new URL("../../../.env", import.meta.url);

const stripInlineComment = (value: string): string => {
  let inSingleQuote = false;
  let inDoubleQuote = false;

  for (let index = 0; index < value.length; index += 1) {
    const character = value[index];
    const previousCharacter = index > 0 ? value[index - 1] : "";

    if (character === '"' && !inSingleQuote) {
      inDoubleQuote = !inDoubleQuote;
      continue;
    }

    if (character === "'" && !inDoubleQuote) {
      inSingleQuote = !inSingleQuote;
      continue;
    }

    if (
      character === "#" &&
      !inSingleQuote &&
      !inDoubleQuote &&
      (index === 0 || /\s/.test(previousCharacter))
    ) {
      return value.slice(0, index).trimEnd();
    }
  }

  return value;
};

const parseEnvValue = (rawValue: string): string => {
  const trimmedValue = stripInlineComment(rawValue).trim();

  if (
    (trimmedValue.startsWith('"') && trimmedValue.endsWith('"')) ||
    (trimmedValue.startsWith("'") && trimmedValue.endsWith("'"))
  ) {
    return trimmedValue.slice(1, -1);
  }

  return trimmedValue;
};

const parseEnvLine = (
  line: string,
): { key: string; value: string } | null => {
  const trimmedLine = line.trim();

  if (!trimmedLine || trimmedLine.startsWith("#")) {
    return null;
  }

  const separatorIndex = trimmedLine.indexOf("=");

  if (separatorIndex <= 0) {
    return null;
  }

  const key = trimmedLine.slice(0, separatorIndex).trim();
  const value = parseEnvValue(trimmedLine.slice(separatorIndex + 1));

  if (!key) {
    return null;
  }

  return { key, value };
};

export const ensureEnvLoaded = (): void => {
  if (didLoadEnv) {
    return;
  }

  didLoadEnv = true;

  let fileContent: string;

  try {
    fileContent = Deno.readTextFileSync(ENV_FILE_URL);
  } catch (error) {
    if (error instanceof Deno.errors.NotFound) {
      return;
    }

    throw error;
  }

  for (const line of fileContent.split(/\r?\n/)) {
    const parsed = parseEnvLine(line);

    if (!parsed) {
      continue;
    }

    if (Deno.env.get(parsed.key) === undefined) {
      Deno.env.set(parsed.key, parsed.value);
    }
  }
};

import { LOG } from "@/tools/logger/index.ts";
import { loadOptionalEnv } from "@/config/env/load-optional-env.ts";
import { loadRequiredEnv } from "@/config/env/load-required-env.ts";
import { ENV_VAR_DETAIL, type EnvVar } from "@/config/env/variables.ts";

export const loadEnv = (key: EnvVar): string => {
  const detail = ENV_VAR_DETAIL[key];

  LOG.trace(`Loading env var ${key} (required: ${detail.required})`);
  try {
    const envVar = detail.required
      ? loadRequiredEnv(key)
      : loadOptionalEnv(key) || detail.default;

    LOG.debug(`Loaded env var ${key}: ${detail.obfuscate ? "****" : envVar}`);

    return envVar;
  } catch (error) {
    LOG.error(`Failed to load env var ${key}: ${error}`);
    Deno.exit(1);
  }
};

import { ensureEnvLoaded } from "@/config/env/bootstrap.ts";

export const loadOptionalEnv = (key: string): string | undefined => {
  ensureEnvLoaded();
  return Deno.env.get(key);
};

import { ensureEnvLoaded } from "@/config/env/bootstrap.ts";

export const loadRequiredEnv = (key: string): string => {
  ensureEnvLoaded();
  const value = Deno.env.get(key);
  if (!value) {
    throw new Error(`Required environment variable ${key} is not set. `);
  }
  return value;
};

export type EnvVar =
  | "DB_HOST"
  | "DB_PORT"
  | "DB_NAME"
  | "DB_USER"
  | "DB_PASSWORD"
  | "LOG_LEVEL"
  | "PORT";

export const ENV_VAR_DETAIL: Record<EnvVar, EnvVarDetail> = {
  ["DB_HOST"]: { required: false, default: "127.0.0.1" },
  ["DB_PORT"]: { required: false, default: "5432" },
  ["DB_NAME"]: {
    required: false,
    default: "__CURIO_PROJECT_DB_IDENTIFIER__",
  },
  ["DB_USER"]: {
    required: false,
    default: "__CURIO_PROJECT_DB_IDENTIFIER__",
  },
  ["DB_PASSWORD"]: {
    required: false,
    default: "__CURIO_PROJECT_DB_IDENTIFIER__",
    obfuscate: true,
  },
  ["LOG_LEVEL"]: { required: false, default: "INFO" },
  ["PORT"]: { required: false, default: "8000" },
};

type EnvVarDetailBase = {
  required: boolean;
  obfuscate?: boolean;
};

type RequiredEnvVarDetail = EnvVarDetailBase & {
  required: true;
  default?: string;
};

type OptionalEnvVarDetail = EnvVarDetailBase & {
  required: false;
  default: string;
};

export type EnvVarDetail = RequiredEnvVarDetail | OptionalEnvVarDetail;

import type { AppConfig } from "@/config/types.ts";
import { loadEnv } from "@/config/env/load-env.ts";

const parseIntegerEnv = (key: "PORT" | "DB_PORT"): number => {
  const rawValue = loadEnv(key);
  const value = Number(rawValue);

  if (!Number.isInteger(value) || value <= 0) {
    throw new Error(`Environment variable ${key} must be a positive integer.`);
  }

  return value;
};

const dbHost = loadEnv("DB_HOST");
const dbPort = parseIntegerEnv("DB_PORT");
const dbName = loadEnv("DB_NAME");
const dbUser = loadEnv("DB_USER");
const dbPassword = loadEnv("DB_PASSWORD");

export const CONFIG: AppConfig = {
  port: parseIntegerEnv("PORT"),
  database: {
    host: dbHost,
    port: dbPort,
    name: dbName,
    user: dbUser,
    password: dbPassword,
    url: `postgresql://${encodeURIComponent(dbUser)}:${
      encodeURIComponent(dbPassword)
    }@${dbHost}:${dbPort}/${encodeURIComponent(dbName)}`,
  },
};

export type DatabaseConfig = {
  host: string;
  port: number;
  name: string;
  user: string;
  password: string;
  url: string;
};

export type AppConfig = {
  port: number;
  database: DatabaseConfig;
};

import {
  findExistingSuperadmin,
  DEFAULT_ROLE_KEYS,
  syncUserRoles,
} from "@curio/core/admin/modules/rbac";
import { hashPassword } from "@curio/core/auth";

type UserRecord = {
  id: string;
  email: string;
  passwordHash: string;
  createdAt: Date;
  updatedAt: Date;
};

type RoleRecord = {
  id: string;
  key: string;
};

type UserRepository = {
  create(
    input: Pick<UserRecord, "email" | "passwordHash">,
  ): Promise<UserRecord>;
};

type RoleRepository = {
  findOne(
    options?: { where?: Partial<Pick<RoleRecord, "key">> },
  ): Promise<RoleRecord | null>;
};

type AppDatabase = {
  User: UserRepository;
  Role: RoleRepository;
  transaction<TResult>(
    operation: (database: AppDatabase) => Promise<TResult>,
  ): Promise<TResult>;
};

export class SuperAdminAlreadyExistsError extends Error {
  constructor(email: string) {
    super(`A superadmin already exists for ${email}.`);
    this.name = "SuperAdminAlreadyExistsError";
  }
}

export type CreateSuperAdminInput = {
  email: string;
  password: string;
  db: AppDatabase;
};

/**
 * Creates the first application superadmin account.
 *
 * @param input Superadmin creation input.
 * @returns The created user entity.
 *
 * @remarks
 * The database must already be prepared and seeded with the built-in admin
 * roles before this helper runs.
 */
export const createSuperAdmin = async (
  input: CreateSuperAdminInput,
): Promise<UserRecord> => {
  const email = input.email.trim().toLowerCase();

  if (!email) {
    throw new Error("Superadmin email cannot be empty.");
  }

  if (!input.password) {
    throw new Error("Superadmin password cannot be empty.");
  }

  const existingSuperAdmin = await findExistingSuperadmin(
    input.db as Parameters<typeof findExistingSuperadmin>[0],
  );

  if (existingSuperAdmin) {
    throw new SuperAdminAlreadyExistsError(existingSuperAdmin.email);
  }

  const superadminRole = await input.db.Role.findOne({
    where: {
      key: DEFAULT_ROLE_KEYS.superadmin,
    },
  });

  if (!superadminRole) {
    throw new Error("Built-in superadmin role has not been seeded.");
  }

  const passwordHash = await hashPassword(input.password);

  return await input.db.transaction(async (tx) => {
    const user = await tx.User.create({
      email,
      passwordHash,
    });

    await syncUserRoles(
      tx as Parameters<typeof syncUserRoles>[0],
      user.id,
      [superadminRole.id],
    );

    return user;
  });
};

import { Database, valibotSchemaAdapter } from "@curio/core";
import { seedDefaultAdminData } from "@curio/core/admin/modules/rbac";
import { drizzleAdapter } from "@curio/core/drizzle";
import postgres from "@postgres";
import { CONFIG } from "@/config/index.ts";
import { databaseTables } from "@/db/tables/index.ts";
import { LOG } from "@/tools/logger/index.ts";

const databaseClient = postgres(CONFIG.database.url, {
  onnotice: () => {},
});

export const db = Database.create({
  adapter: drizzleAdapter({
    dialect: "postgres",
    client: databaseClient,
  }),
  schemaAdapter: valibotSchemaAdapter,
  tables: databaseTables,
});

export const prepareDatabase = async (): Promise<void> => {
  LOG.debug("Preparing Curio database schema", "prepareDatabase");
  await db.prepare();
  LOG.debug("Database schema prepared", "prepareDatabase");
  LOG.debug(
    "Seeding built-in admin roles and permissions",
    "prepareDatabase",
  );
  await seedDefaultAdminData(db);
  LOG.debug(
    "Built-in admin roles and permissions ready",
    "prepareDatabase",
  );
};

export const closeDatabase = async (): Promise<void> => {
  LOG.debug("Ending Postgres client", "closeDatabase");
  await databaseClient.end({ timeout: 5 });
};

export { User, UserEntity, UserModel } from "@/db/tables/user.ts";

export {
  AuditEvent,
  AuditEventEntity,
  AuditEventModel,
  Permission,
  PermissionEntity,
  PermissionModel,
  Role,
  RoleEntity,
  RoleModel,
  RolePermission,
  RolePermissionEntity,
  RolePermissionModel,
  Session,
  SessionEntity,
  SessionModel,
  UserRole,
  UserRoleEntity,
  UserRoleModel,
} from "@curio/core/admin";

import { User } from "@/db/tables/user.ts";
import {
  AuditEvent,
  Permission,
  Role,
  RolePermission,
  Session,
  UserRole,
} from "@curio/core/admin";

/** Full backend table registry consumed by `Database.create(...)`. */
export const databaseTables = {
  User,
  Role,
  Permission,
  UserRole,
  RolePermission,
  Session,
  AuditEvent,
} as const;

import * as v from "@valibot/valibot";
import {
  Entity,
  field,
  Model,
  relation,
  Timestamps,
  UuidPrimaryKey,
} from "@curio/core";

const userCreateValidationSchema = v.object({
  id: v.optional(v.string()),
  email: v.pipe(v.string(), v.email()),
  passwordHash: v.string(),
  createdAt: v.optional(v.date()),
  updatedAt: v.optional(v.date()),
});

const userUpdateValidationSchema = v.partial(v.object({
  email: v.pipe(v.string(), v.email()),
  passwordHash: v.string(),
  updatedAt: v.optional(v.date()),
}));

/**
 * Application user model consumed by Curio admin auth.
 *
 * @remarks
 * Roles are normalized through the `UserRole` join table rather than stored as
 * a direct enum on the user row.
 */
export const UserModel = new Model({
  name: "User",
  table: "users",
  uses: [UuidPrimaryKey, Timestamps],
  fields: {
    email: field.string().required().unique().sortable(),
    passwordHash: field.string().required().hidden().searchable(false),
  },
  relations: {
    userRoles: relation.hasMany("UserRole").foreignKey("userId"),
    sessions: relation.hasMany("Session").foreignKey("userId"),
    auditEvents: relation.hasMany("AuditEvent").foreignKey("actorUserId"),
  },
  defaultOrder: [{ createdAt: "desc" }],
  validation: {
    create: userCreateValidationSchema,
    update: userUpdateValidationSchema,
  },
});

/** Hydrated application user entity returned by Curio repositories. */
export class UserEntity extends Entity {
  declare id: string;
  declare email: string;
  declare passwordHash: string;
  declare createdAt: Date;
  declare updatedAt: Date;

  get emailDomain(): string {
    return this.email.split("@")[1] ?? "";
  }
}

/** Bound application user entity registration for `Database.create(...)`. */
export const User = UserEntity.from(UserModel);

import { Admin } from "@curio/core/admin";
import { db } from "@/db/index.ts";

/** Starter Curio admin mounted at `/admin`. */
export const admin = Admin.create({
  db,
  presets: ["default"],
  branding: {
    name: "__CURIO_PROJECT_NAME__ Admin",
    tagline: "Control room.",
  },
});

import * as v from "@valibot/valibot";
