export type AppHealthStatus = "starting" | "ready" | "stopping" | "stopped";

export type AppHealthSnapshot = {
  status: AppHealthStatus;
  healthy: boolean;
  uptimeMs: number;
  timestamp: string;
};

type AppHealthState = {
  status: AppHealthStatus;
  startedAt: number;
};

const DEFAULT_STATUS: AppHealthStatus = "starting";

let appHealthState: AppHealthState = {
  status: DEFAULT_STATUS,
  startedAt: Date.now(),
};

const isHealthyStatus = (status: AppHealthStatus): boolean => {
  return status === "ready";
};

export const setAppHealthStatus = (status: AppHealthStatus): void => {
  appHealthState = {
    ...appHealthState,
    status,
  };
};

export const resetAppHealthState = (
  status: AppHealthStatus = DEFAULT_STATUS,
): void => {
  appHealthState = {
    status,
    startedAt: Date.now(),
  };
};

export const getAppHealthSnapshot = (): AppHealthSnapshot => {
  return {
    status: appHealthState.status,
    healthy: isHealthyStatus(appHealthState.status),
    uptimeMs: Math.max(0, Date.now() - appHealthState.startedAt),
    timestamp: new Date().toISOString(),
  };
};

import type { Middleware } from "@oak/oak";
import { LOG } from "@/tools/logger/index.ts";

const getRequestIpAddress = (
  request: { headers: Headers; ip?: string },
): string => {
  const forwardedFor = request.headers.get("x-forwarded-for");

  if (forwardedFor) {
    return forwardedFor.split(",")[0]?.trim() ?? "unknown";
  }

  return request.ip ?? "unknown";
};

const formatDuration = (startedAt: number): string => {
  const durationMs = performance.now() - startedAt;
  return `${durationMs.toFixed(1)}ms`;
};

const formatRequestSummary = (
  method: string,
  path: string,
  status: number,
  duration: string,
  ipAddress: string,
): string => {
  return `${method} ${path} -> ${status} in ${duration} (${ipAddress})`;
};

const isLowSignalPath = (path: string): boolean => {
  return path === "/health" || path.startsWith("/admin/assets/");
};

const isReadOnlyMethod = (method: string): boolean => {
  return method === "GET" || method === "HEAD" || method === "OPTIONS";
};

export const requestLoggingMiddleware: Middleware = async (ctx, next) => {
  const startedAt = performance.now();
  const method = ctx.request.method;
  const path = ctx.request.url.pathname;
  const ipAddress = getRequestIpAddress(ctx.request);

  try {
    await next();
  } catch (error) {
    const duration = formatDuration(startedAt);
    const message = error instanceof Error ? error.message : String(error);
    LOG.error(
      `${method} ${path} failed in ${duration} (${ipAddress}): ${message}`,
      "requestLoggingMiddleware",
    );
    throw error;
  }

  const status = ctx.response.status || 404;
  const duration = formatDuration(startedAt);
  const summary = formatRequestSummary(
    method,
    path,
    status,
    duration,
    ipAddress,
  );

  if (status >= 500) {
    LOG.error(summary, "requestLoggingMiddleware");
    return;
  }

  if (status >= 400) {
    LOG.warn(summary, "requestLoggingMiddleware");
    return;
  }

  if (isLowSignalPath(path) || isReadOnlyMethod(method) && path === "/") {
    LOG.debug(summary, "requestLoggingMiddleware");
    return;
  }

  LOG.info(summary, "requestLoggingMiddleware");
};

import { Application } from "@oak/oak";
import { CONFIG } from "@/config/index.ts";
import { closeDatabase, prepareDatabase } from "@/db/index.ts";
import { admin } from "@/http/admin/index.ts";
import { httpApi } from "@/http/api/index.ts";
import { setAppHealthStatus } from "@/http/health/state.ts";
import { requestLoggingMiddleware } from "@/http/middleware/request-logging.ts";
import { LOG } from "@/tools/logger/index.ts";

const SHUTDOWN_TIMEOUT_MS = 5_000;

export const createHttpServer = (): Application => {
  const app = new Application();

  app.use(requestLoggingMiddleware);
  admin.mount(app);
  app.use(httpApi.routes());
  app.use(httpApi.allowedMethods());

  return app;
};

export const startHttpServer = async (): Promise<void> => {
  LOG.debug("Creating HTTP server");
  const app = createHttpServer();
  const abortController = new AbortController();
  let shuttingDown = false;
  let forceExitTimer: number | undefined;

  const clearForceExitTimer = () => {
    if (forceExitTimer === undefined) {
      return;
    }

    clearTimeout(forceExitTimer);
    forceExitTimer = undefined;
  };

  const scheduleForceExit = () => {
    if (forceExitTimer !== undefined) {
      return;
    }

    forceExitTimer = setTimeout(() => {
      LOG.warn("Shutdown timed out. Forcing process exit.");
      Deno.exit(130);
    }, SHUTDOWN_TIMEOUT_MS);
  };

  const removeShutdownListeners = () => {
    Deno.removeSignalListener("SIGINT", handleShutdownSignal);
    Deno.removeSignalListener("SIGTERM", handleShutdownSignal);
  };

  const handleShutdownSignal = () => {
    if (shuttingDown) {
      LOG.warn("Shutdown already in progress. Forcing process exit.");
      Deno.exit(130);
    }

    shuttingDown = true;
    removeShutdownListeners();
    scheduleForceExit();
    setAppHealthStatus("stopping");
    LOG.info("HTTP server shutting down");
    abortController.abort();
  };

  app.addEventListener("listen", () => {
    setAppHealthStatus("ready");
    LOG.info(`HTTP server listening on http://localhost:${CONFIG.port}`);
  });

  app.addEventListener("close", () => {
    setAppHealthStatus("stopped");
    LOG.info("HTTP server stopped");
  });

  setAppHealthStatus("starting");
  Deno.addSignalListener("SIGINT", handleShutdownSignal);
  Deno.addSignalListener("SIGTERM", handleShutdownSignal);

  try {
    LOG.info("Preparing database before accepting traffic");
    await prepareDatabase();
    LOG.info("Database ready");
    LOG.debug("Admin mounted at /admin");
    LOG.debug("API routes mounted");

    await app.listen({
      port: CONFIG.port,
      signal: abortController.signal,
    });
  } finally {
    removeShutdownListeners();

    try {
      LOG.debug("Closing database connection");
      await closeDatabase();
      LOG.debug("Database connection closed");
    } finally {
      clearForceExitTimer();
    }
  }
};

if (import.meta.main) {
  await startHttpServer();
}

import { loadOptionalEnv } from "@/config/env/load-optional-env.ts";
import { Color, ColorCodes, LogLevel } from "@/tools/logger/types.ts";

const DEFAULT_LOG_LEVEL_NAME = "INFO";

const resolveLogLevel = (): LogLevel => {
  const rawValue = loadOptionalEnv("LOG_LEVEL");
  const normalizedValue = rawValue?.trim().toUpperCase() ??
    DEFAULT_LOG_LEVEL_NAME;
  const resolvedLevel = LogLevel[
    normalizedValue as keyof typeof LogLevel
  ];

  if (typeof resolvedLevel === "number") {
    return resolvedLevel;
  }

  console.warn(
    `Invalid LOG_LEVEL "${rawValue}". Falling back to ${DEFAULT_LOG_LEVEL_NAME}.`,
  );

  return LogLevel[DEFAULT_LOG_LEVEL_NAME];
};

class Logger {
  private logLevel: LogLevel;
  constructor(logLevel: LogLevel) {
    this.logLevel = logLevel;
    this.info(`Logger initialized with level: ${this.getLogLevelName()}`);
  }

  private highlightText(text: string, color: Color): string {
    return `${ColorCodes[color]}${text}${ColorCodes[Color.RESET]}`;
  }

  private log(
    message: string,
    level: LogLevel = LogLevel.INFO,
    prefixColor: Color = Color.RESET,
    messageColor: Color = Color.RESET,
    fnName?: string,
  ): void {
    const timestamp = new Date().toISOString();
    const prefix = `[${timestamp}::${LogLevel[level]}${
      fnName ? " - " + this.highlightText(fnName, Color.MAGENTA) : ""
    }]`;
    const coloredMessage = this.highlightText(message, messageColor);
    const coloredPrefix = this.highlightText(prefix, prefixColor);
    console.log(`${coloredPrefix} ${coloredMessage}`);
  }

  public getLogLevel(): LogLevel {
    return this.logLevel;
  }
  public getLogLevelName(): string {
    return LogLevel[this.logLevel];
  }

  public trace(message: string, fnName?: string) {
    if (this.logLevel >= LogLevel.TRACE) {
      this.log(message, LogLevel.TRACE, Color.RESET, Color.RESET, fnName);
    }
  }

  public debug(message: string, fnName?: string) {
    if (this.logLevel >= LogLevel.DEBUG) {
      this.log(message, LogLevel.DEBUG, Color.GREEN, Color.LIGHT_GREEN, fnName);
    }
  }
  public info(message: string, fnName?: string) {
    if (this.logLevel >= LogLevel.INFO) {
      this.log(message, LogLevel.INFO, Color.BLUE, Color.LIGHT_BLUE, fnName);
    }
  }

  public warn(message: string, fnName?: string) {
    if (this.logLevel >= LogLevel.WARN) {
      this.log(
        message,
        LogLevel.WARN,
        Color.YELLOW,
        Color.LIGHT_YELLOW,
        fnName,
      );
    }
  }

  public error(message: string, fnName?: string) {
    if (this.logLevel >= LogLevel.ERROR) {
      this.log(message, LogLevel.ERROR, Color.RED, Color.LIGHT_RED, fnName);
    }
  }
  public fatal(message: string, fnName?: string) {
    if (this.logLevel >= LogLevel.FATAL) {
      this.log(message, LogLevel.FATAL, Color.DARK_RED, Color.RED, fnName);
    }
  }
}

export const LOG = new Logger(resolveLogLevel());
